mapper.select:
SELECT ID, EDU_START_AT, USER_ID, EDU_ID, EDU_START_IS_COMPLETED, EDU_START_TOTAL_COUNT, EDU_START_COMPLETED_COUNT, EDU_START_CORRECT_COUNT
FROM (
    SELECT ID, EDU_START_AT, USER_ID, EDU_ID, EDU_START_IS_COMPLETED, EDU_START_TOTAL_COUNT, EDU_START_COMPLETED_COUNT, EDU_START_CORRECT_COUNT
    FROM TBL_EDU_START
    WHERE USER_ID = #{userId}
        AND EDU_ID = #{eduId}
        AND EDU_START_IS_COMPLETED = 0
    ORDER BY EDU_START_AT DESC
)
WHERE ROWNUM = 1

mapper.update:
UPDATE TBL_EDU_START
SET EDU_START_IS_COMPLETED = 1,
    EDU_START_COMPLETED_AT = CURRENT_TIMESTAMP,
    EDU_START_TIME = #{eduStartTime}
WHERE ID = (
    SELECT ID
    FROM (
             SELECT ID
             FROM TBL_EDU_START
             WHERE USER_ID = #{userId}
               AND EDU_ID = #{eduId}
               AND EDU_START_IS_COMPLETED = 0
             ORDER BY EDU_START_AT DESC
         )
    WHERE ROWNUM = 1
)

UPDATE TBL_EDU_START
SET EDU_START_COMPLETED_COUNT = EDU_START_COMPLETED_COUNT + 1,
    EDU_START_CORRECT_COUNT = EDU_START_CORRECT_COUNT + #{isCorrect}
WHERE ID = #{id}
  AND EDU_START_IS_COMPLETED = 0
  AND EDU_START_COMPLETED_COUNT < EDU_START_TOTAL_COUNT

